"use client";

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import styles from './Sidebar.module.css';

interface NavItem {
  label: string;
  href: string;
  icon: string;
}

const navItems: NavItem[] = [
  { label: 'Dashboard', href: '/', icon: '📊' },
  { label: 'POS / Kasir', href: '/pos', icon: '🛒' },
  { label: 'Inventaris', href: '/inventory', icon: '📦' },
  { label: 'Pelanggan', href: '/customers', icon: '👥' },
  { label: 'Kendaraan', href: '/vehicles', icon: '🚗' },
  { label: 'Mekanik', href: '/mechanics', icon: '👨‍🔧' },
  { label: 'Keuangan', href: '/finance', icon: '💰' },
];

const settingsItems: NavItem[] = [
  { label: 'Audit Logs', href: '/audit-logs', icon: '📜' },
  { label: 'Pengaturan', href: '/settings', icon: '⚙️' },
];

export const Sidebar: React.FC = () => {
  const pathname = usePathname();

  return (
    <aside className={styles.sidebar}>
      <nav className={styles.nav}>
        {navItems.map((item) => (
          <Link
            key={item.href}
            href={item.href}
            className={`${styles.navItem} ${
              pathname === item.href ? styles.active : ''
            }`}
          >
            <span className={styles.icon}>{item.icon}</span>
            <span className={styles.label}>{item.label}</span>
          </Link>
        ))}

        <div className={styles.navDivider}></div>

        {settingsItems.map((item) => (
          <Link
            key={item.href}
            href={item.href}
            className={`${styles.navItem} ${
              pathname === item.href ? styles.active : ''
            }`}
          >
            <span className={styles.icon}>{item.icon}</span>
            <span className={styles.label}>{item.label}</span>
          </Link>
        ))}
      </nav>
    </aside>
  );
};
